def range_summary(nums):
    if not nums:
        return ""

    sorted_nums = sorted(set(nums))
    ranges = []
    start = end = None

    for num in sorted_nums:
        if start is None or num == end + 1:
            if start is None:
                start = num
            end = num
        else:
            if start != end:
                ranges.append(f"{start}-{end}")
            start = end = num

    if start != end:
        ranges.append(f"{start}-{end}")

    return ",".join(ranges)
